+    fn seed_hash_field_ttl_store() -> Store {
+        let mut store = Store::new();
+        dispatch_argv(
+            &[
+                b"HSET".to_vec(),
+                b"h".to_vec(),
+                b"f1".to_vec(),
+                b"v1".to_vec(),
+                b"f2".to_vec(),
+                b"v2".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .expect("hset");
+        store
+    }
+
+    #[test]
+    fn hexpire_sets_ttl_and_returns_applied_code() {
+        let mut store = seed_hash_field_ttl_store();
+        let out = dispatch_argv(
+            &[
+                b"HEXPIRE".to_vec(),
+                b"h".to_vec(),
+                b"60".to_vec(),
+                b"FIELDS".to_vec(),
+                b"2".to_vec(),
+                b"f1".to_vec(),
+                b"missing".to_vec(),
+            ],
+            &mut store,
+            1_000,
+        )
+        .expect("hexpire");
+        assert_eq!(
+            out,
+            RespFrame::Array(Some(vec![
+                RespFrame::Integer(1),  // f1 applied
+                RespFrame::Integer(-2), // missing field
+            ]))
+        );
+        // HTTL reads it back.
+        let ttl = dispatch_argv(
+            &[
+                b"HTTL".to_vec(),
+                b"h".to_vec(),
+                b"FIELDS".to_vec(),
+                b"1".to_vec(),
+                b"f1".to_vec(),
+            ],
+            &mut store,
+            1_000,
+        )
+        .expect("httl");
+        assert_eq!(ttl, RespFrame::Array(Some(vec![RespFrame::Integer(60)])));
+    }
